// Alert triggers when the Apache server load (1-minute average) exceeds the threshold.
// High server load indicates the server is under heavy demand and may experience performance degradation.
// The alert is grouped by host name.
// You can adjust the threshold value by modifying the server_load in the WHERE clause (default: > 0.8 = 80%).
FROM metrics-apachereceiver.otel-*
| STATS server_load = AVG(metrics.apache.load.1) BY resource.attributes.host.name
| WHERE server_load IS NOT NULL AND server_load > 0.8
| EVAL server_load = ROUND(server_load, 3)
| KEEP resource.attributes.host.name, server_load
| SORT server_load DESC
